// DATA — FICHES (généré depuis Notion)
// =============================================
const FICHES = [
  {num:1,title:"Définition et sources du droit du travail",partie:"1 — Sources et contrôle",content:"<h2>Fiche 1 — Définition et sources du droit du travail</h2><p>Le droit du travail est l'ensemble des règles juridiques applicables aux relations individuelles et collectives entre les employeurs privés et leurs salariés. Son but est de protéger les salariés tout en prenant en compte la protection de l'emploi.</p><h3>1. Caractéristiques</h3><ul><li>Droit récent</li><li>Droit étatique : ordre public social</li><li>Droit négocié : rôle essentiel des partenaires sociaux</li></ul><h3>2. Sources supra-étatiques</h3><h4>Sources internationales</h4><ul><li>OIT : conventions et recommandations, aucun moyen de contrainte</li><li>Conseil de l'Europe (46 États) : Convention EDH (1950), Charte sociale européenne (1961)</li></ul><h4>Sources communautaires</h4><ul><li>Traités, Charte des droits fondamentaux (2007)</li><li>Directives (nécessitent transposition) et règlements (application directe)</li><li>Jurisprudence de la CJUE</li></ul><h4>Sources nationales</h4><ul><li>Constitution → loi → règlements</li><li>Jurisprudence (interprète et précise la loi)</li></ul><h3>3. Sources professionnelles</h3><ul><li>ANI, accords de branche, accords d'entreprise</li><li>Usage : généralité + constance + fixité</li><li>Engagement unilatéral : explicite, sans condition</li></ul><div class=\"key-point\">⚠️ Ordonnances Macron : L'accord d'entreprise prime sur l'accord de branche (fin du principe de faveur automatique), sauf dans les domaines verrouillés.</div><h3>4. Dénonciation d'un usage</h3><ul><li>Informer les représentants du personnel</li><li>Informer tous les salariés individuellement</li><li>Respecter un préavis raisonnable</li></ul><h3><strong>5. Hiérarchie des normes</strong></h3>"},
  {num:2,title:"Le conseil de prud'hommes",partie:"1 — Sources et contrôle",content:"<h2>Fiche 2 — Le conseil de prud'hommes</h2><p>Juridiction paritaire compétente pour tous les litiges individuels nés à l'occasion d'un contrat de travail.</p><h3>1. Délais de recours</h3><h3>2. Procédure</h3><ul><li>BCO (Bureau de Conciliation et d'Orientation) : phase obligatoire, à huis clos</li><li>Bureau de jugement en cas d'échec de conciliation</li><li>Juge départiteur (TJ) en cas de partage des voix</li></ul><div class=\"key-point\">Appel : Possible si demande &gt; 5 000 €, dans le délai d'1 mois (suspensif). En dessous → pourvoi en cassation uniquement (2 mois).</div><h3>3. Barème licenciement sans cause réelle et sérieuse (≥ 11 salariés)</h3>"},
  {num:3,title:"L'inspection du travail",partie:"1 — Sources et contrôle",content:"<h2>Fiche 3 — L'inspection du travail</h2><p>Mission : assurer le respect de la législation du travail, conseiller et concilier.</p><h3>1. Pouvoirs</h3><ul><li>Droit de visite sans prévenir l'employeur</li><li>Droit de communication de tous documents légaux</li><li>Autoriser/interdire le licenciement des salariés protégés</li><li>Contrôler le règlement intérieur</li></ul><h3>2. Éventail des sanctions</h3><h3>3. Amendes administratives (DREETS)</h3><ul><li>4 000 €/salarié pour manquements durée travail, salaire, locaux</li><li>8 000 € en cas de récidive dans les 2 ans</li><li>10 000 €/salarié pour manquements santé/sécurité</li></ul><div class=\"key-point\">Délit d'entrave : 37 500 € + 1 an de prison pour obstruction à la mission de l'inspecteur.</div>"},
  {num:4,title:"L'embauche",partie:"2 — Embauche et contrats",content:"<h2>Fiche 4 — L'embauche</h2><h3>1. Non-discrimination</h3><p>Aucune discrimination fondée sur l'origine, le sexe, l'âge, la religion, l'état de santé… (art. L1132-1).</p><h3>2. Offre vs Promesse d'embauche (Revirement 2017)</h3><ul><li>Offre : L'employeur peut se rétracter avant acceptation (responsabilité civile uniquement).</li><li>Promesse unilatérale : La rétractation = licenciement sans cause réelle et sérieuse.</li></ul><h3>3. Formalités obligatoires</h3><ul><li>DPAE à l'Urssaf : au plus tôt 8 jours avant, au plus tard la veille</li><li>Registre unique du personnel dans l'ordre d'embauche</li></ul><div class=\"key-point\">Écrit CDI : Remis dans la 1re semaine.</div><h3>4. Travail dissimulé</h3><ul><li>Sanctions pénales : 3 ans prison + 45 000 €</li><li>Indemnité salarié : 6 mois de salaire forfaitaire</li></ul>"},
  {num:5,title:"Le contrat de travail et ses clauses",partie:"2 — Embauche et contrats",content:"<h2>Fiche 5 — Le contrat de travail et ses clauses</h2><h3>1. Les 3 critères du contrat de travail</h3><p>Prestation de travail + rémunération + lien de subordination juridique (critère décisif).</p><div class=\"key-point\">Plateformes (Uber, Deliveroo) : La Cour de cassation requalifie régulièrement les travailleurs indépendants en salariés si l'algorithme caractérise un lien de subordination.</div><h3>2. Période d'essai (CDI)</h3><h3>3. Clauses autorisées</h3><ul><li>Non-concurrence : 5 conditions cumulatives dont contrepartie financière obligatoire</li><li>Mobilité : Zone géographique précise, bonne foi</li><li>Dédit-formation : Remboursement si départ prématuré</li></ul><h3>4. Clauses interdites</h3><ul><li>Couperet (rupture automatique à un âge) : nulle</li><li>Compromissoire (arbitre privé à la place des prud'hommes) : nulle</li><li>Célibat : nulle</li></ul>"},
  {num:6,title:"Les différents contrats de travail",partie:"2 — Embauche et contrats",content:"<h2>Fiche 6 — Les différents contrats de travail</h2><h3>1. CDD — Cas de recours interdits</h3><ul><li>Remplacement d'un salarié gréviste</li><li>Travaux particulièrement dangereux (sauf dérogation)</li><li>Dans les 6 mois suivant un licenciement économique</li></ul><h3>2. Durées maximales CDD</h3><div class=\"key-point\">Renouvellement : 2 fois max. Délai de carence : 1/3 de la durée (1/2 si CDD &lt; 15 jours).</div><h3>3. Fin du CDD</h3><ul><li>Indemnité de précarité : 10 % du salaire brut</li><li>Indemnité de congés payés : 10 %</li></ul><h3>4. Travail temporaire</h3><ul><li>Contrat de mise à disposition + contrat de mission</li><li>Fin de mission : 10 % + CP : 10 %</li></ul><h3>5. Portage salarial</h3><p>Rémunération : 70 à 85 % du plafond SS + 5 % d'apport d'affaires. Durée max chez un même client : 36 mois.</p>"},
  {num:7,title:"Le pouvoir de l'employeur",partie:"3 — Exécution du contrat",content:"<h2>Fiche 7 — Le pouvoir de l'employeur</h2><h3>1. Règlement intérieur</h3><ul><li>Obligatoire : entreprises ≥ 50 salariés (12 mois consécutifs)</li><li>4 domaines uniquement : santé/sécurité, discipline, droits de la défense, rappel harcèlement</li><li>Procédure : avis CSE → inspecteur du travail → dépôt → affichage</li><li>Entre en vigueur 1 mois minimum après dépôt</li></ul><h3>2. Sanctions disciplinaires</h3><div class=\"key-point\">Prescription : 2 mois après connaissance de la faute. Une faute ne peut être sanctionnée qu'une fois. Effacement après 3 ans.</div><h3>3. Surveillance</h3><ul><li>Messages ordi pro = présumés professionnels</li><li>Fichiers \"personnels\" = vie privée protégée</li><li>Tout système de contrôle déclaré au CSE et au salarié</li></ul>"},
  {num:8,title:"La durée du travail",partie:"3 — Exécution du contrat",content:"<h2>Fiche 8 — La durée du travail</h2><div class=\"key-point\">Durée légale : 35 heures de travail effectif par semaine.</div><h3>1. Heures supplémentaires</h3><ul><li>Contingent annuel : 220 h (sauf accord de branche)</li><li>Majoration légale : 25 % pour les 8 premières h/sem, 50 % au-delà</li><li>Accord d'entreprise : peut descendre à 10 % minimum</li></ul><h3>2. Durées maximales</h3><h3>3. Repos obligatoires</h3><ul><li>Repos quotidien : 11 h consécutives minimum</li><li>Repos hebdomadaire : 35 h consécutives (dimanche en principe)</li><li>Pause : 20 min après 6 h de travail effectif</li></ul><h3>4. Aménagements</h3><ul><li>Annualisation : 1 607 h/an (accord collectif)</li><li>Forfait jours : cadres autonomes uniquement (accord collectif obligatoire)</li><li>Temps partiel : mini 24 h/sem (sauf accord de branche ou demande salarié)</li></ul>"},
  {num:9,title:"Les repos et congés",partie:"3 — Exécution du contrat",content:"<h2>Fiche 9 — Les repos et congés</h2><h3>1. Congés payés</h3><ul><li>2,5 jours ouvrables par mois = 30 jours (5 semaines) par an</li><li>Période de référence : 1er juin au 31 mai</li><li>Congé principal : 4 semaines consécutives entre mai et octobre</li></ul><h3>2. Congés pour événements familiaux</h3><h3>3. Congé parental d'éducation</h3><p>Droit pour tout salarié avec 1 an d'ancienneté, à la naissance ou adoption d'enfant &lt; 3 ans. Durée : 1 an renouvelable 2 fois (jusqu'aux 3 ans de l'enfant).</p><h3>4. Congé paternité</h3><p>25 jours calendaires (32 pour naissances multiples). Obligatoirement pris dans les 6 mois suivant la naissance.</p>"},
  {num:10,title:"La formation professionnelle",partie:"3 — Exécution du contrat",content:"<h2>Fiche 10 — La formation professionnelle</h2><h3>1. Obligations de l'employeur</h3><ul><li>Adapter les salariés à leur poste</li><li>Veiller au maintien de leur employabilité</li><li>Entretien professionnel tous les 2 ans</li></ul><div class=\"key-point\">Sanction bilan 6 ans : Si pas d'entretien tous les 2 ans ET aucune formation → abondement CPF de 3 000 €.</div><h3>2. CPF (Compte Personnel de Formation)</h3><ul><li>Alimentation : 500 €/an (800 € non-qualifiés)</li><li>Plafond : 5 000 € (8 000 € non-qualifiés)</li><li>Attaché à la personne, pas à l'employeur</li><li>Mobilisable sans accord employeur (hors temps de travail)</li></ul><h3>3. Plan de développement des compétences</h3><ul><li>Actions d'adaptation au poste : obligatoires, pendant le temps de travail, rémunérées</li><li>Actions de développement : maintien dans l'emploi ou évolution</li></ul>"},
  {num:11,title:"La santé et la sécurité",partie:"3 — Exécution du contrat",content:"<h2>Fiche 11 — La santé et la sécurité</h2><h3>1. Obligations de l'employeur</h3><ul><li>Obligation de sécurité : prendre toutes les mesures de prévention</li><li>Évaluer les risques et mettre à jour le DUERP</li></ul><h3>2. Accident du travail</h3><ul><li>Survenu par le fait ou à l'occasion du travail</li><li>Présomption d'imputabilité pendant le temps de travail</li><li>Accident de trajet : protection comparable</li></ul><h3>3. Inaptitude</h3><ul><li>Constatée par le médecin du travail</li><li>Obligation de reclassement préalable</li><li>Si impossible → licenciement pour inaptitude</li><li>Indemnité doublée si inaptitude d'origine professionnelle</li></ul><div class=\"key-point\">Harcèlement moral : Agissements répétés dégradant les conditions de travail. Sanction : 2 ans + 30 000 €.</div><div class=\"key-point\">Harcèlement sexuel : Propos ou comportements à connotation sexuelle imposés. Sanction : 2 ans + 30 000 €.</div>"},
  {num:12,title:"Le salaire, participation, intéressement",partie:"3 — Exécution du contrat",content:"<h2>Fiche 12 — Le salaire, la participation et l'épargne salariale</h2><h3>1. Salaire</h3><ul><li>SMIC : revalorisé chaque 1er janvier + automatiquement si inflation &gt; 2 %</li><li>Bulletin de paie obligatoire à chaque paiement</li><li>Égalité de rémunération H/F pour travail de valeur égale</li></ul><h3>2. Protection du salaire</h3><ul><li>Saisie-arrêt limitée selon barème légal</li><li>AGS garantit les salaires impayés en cas de procédure collective</li></ul><h3>3. Participation</h3><p>Obligatoire pour entreprises ≥ 50 salariés. Calculée selon formule légale. Bloquée 5 ans (sauf déblocage anticipé).</p><h3>4. Intéressement</h3><p>Facultatif, lié aux résultats. Accord collectif obligatoire. Bloqué 3 mois minimum.</p><h3>5. PEE / PER collectif</h3><ul><li>PEE : blocage 5 ans</li><li>PER collectif : blocage jusqu'à la retraite</li><li>Abondement employeur exonéré de charges (dans les limites légales)</li></ul>"},
  {num:13,title:"La modification du contrat de travail",partie:"4 — Modification et suspension",content:"<h2>Fiche 13 — La modification du contrat de travail</h2><div class=\"key-point\">Distinction clé : Modification d'un élément essentiel (accord salarié requis) ≠ Changement des conditions de travail (pouvoir de direction unilatéral).</div><h3>1. Éléments essentiels du contrat</h3><ul><li>Rémunération</li><li>Durée du travail</li><li>Lieu de travail (hors secteur géographique ou clause de mobilité)</li><li>Qualification / nature des fonctions</li></ul><h3>2. Procédure pour modification économique</h3><ul><li>Notification au salarié par LRAR</li><li>Délai de réflexion : 1 mois (15 jours en liquidation/redressement)</li><li>Silence = acceptation</li><li>Refus = licenciement économique</li></ul><h3>3. Accord de performance collective</h3><p>Peut modifier rémunération, durée, lieu. Refus du salarié = licenciement pour motif personnel (cause réelle et sérieuse). Délai : 2 mois du refus + abondement CPF.</p><h3>4. Art. L1224-1 — Transfert d'entreprise</h3><p>En cas de vente, fusion, apport partiel… : les contrats de travail se poursuivent automatiquement avec le nouvel employeur aux mêmes conditions.</p>"},
  {num:14,title:"La suspension du contrat de travail",partie:"4 — Modification et suspension",content:"<h2>Fiche 14 — La suspension du contrat de travail</h2><h3>1. Congé maternité</h3><div class=\"key-point\">Interdiction absolue de licencier pendant le congé maternité. Protection relative pendant les 10 semaines suivant le retour (sauf faute grave non liée à la grossesse ou impossibilité de maintenir le contrat pour motif étranger).</div><p>À son retour, la salariée doit : retrouver son poste ou un poste équivalent, bénéficier des augmentations générales attribuées en son absence, et peut prendre ses congés payés même si la période est expirée.</p><h3>2. Congé paternité et d'accueil de l'enfant</h3><ul><li>25 jours calendaires (32 pour naissances multiples)</li><li>4 jours pris immédiatement après le congé de naissance de 3 jours</li><li>Le reste dans les 6 mois suivant la naissance</li><li>Salarié doit prévenir l'employeur 1 mois avant</li></ul><div class=\"key-point\">Protection paternité : Aucun employeur ne peut rompre le contrat pendant les 10 semaines suivant la naissance (sauf faute grave ou impossibilité de maintenir le contrat).</div><h3>3. Maladie ordinaire et accident non professionnel</h3><ul><li>Salarié doit prévenir l'employeur dans les 48 heures</li><li>Adresser le certificat médical dans les 2-3 jours</li><li>Respecter les horaires de sortie : interdiction de sortir entre 9h-11h et 14h-16h</li><li>IJ SS : après 3 jours de carence = 50 % du SJR plafonné</li><li>Visite de reprise obligatoire si arrêt &gt; 30 jours</li></ul><div class=\"key-point\">Licenciement pour maladie : interdit en raison de l'état de santé (discriminatoire = nul). Autorisé uniquement si : inaptitude + reclassement impossible, OU absences prolongées/répétées perturbant l'entreprise et nécessitant un remplacement définitif (CDI, même volume horaire).</div><h3>4. Accident du travail et maladie professionnelle</h3><ul><li>Accident survenu par le fait ou à l'occasion du travail (art. L411-1 CSS)</li><li>Présomption d'imputabilité pendant le temps et sur le lieu de travail</li><li>IJ : versées dès le 1er jour (pas de délai de carence)</li><li>Protection renforcée : licenciement interdit pendant la suspension sauf faute grave ou impossibilité maintien</li><li>Visite de reprise obligatoire si arrêt &gt; 30 jours (AT) ou quelle que soit la durée (maladie pro)</li></ul><div class=\"key-point\">Inaptitude d'origine professionnelle : indemnité de licenciement doublée + indemnités de préavis. Si refus injustifié de reclassement : droit commun uniquement.</div><h3>5. Accident de trajet</h3><p>Accident survenu pendant le trajet entre la résidence et le lieu de travail, ou entre le lieu de travail et le lieu de restauration habituel. Certains détours sont admis (covoiturage régulier, conduire un enfant à l'école, courses essentielles).</p><div class=\"key-point\">Différence AT/trajet : L'accident de trajet a les mêmes incidences que la maladie ordinaire (pas la protection renforcée de l'AT). Pas de faute inexcusable de l'employeur possible.</div><h3>6. Accident de mission</h3><p>Accident survenu lors d'un déplacement professionnel pour le compte de l'employeur. Considéré comme un accident du travail (protection renforcée), même s'il survient lors d'un acte de la vie courante pendant la mission. Le trajet aller/retour de mission = AT (pas accident de trajet).</p><h3>7. Congé parental d'éducation</h3><ul><li>Droit pour tout salarié avec 1 an d'ancienneté à la naissance ou adoption d'un enfant &lt; 3 ans</li><li>Durée : 1 an renouvelable 2 fois (jusqu'aux 3 ans de l'enfant)</li><li>Contrat suspendu pendant le congé parental</li><li>Préavis : 1 mois si le congé suit le congé maternité ; 2 mois sinon</li><li>À l'issue : retrouver son emploi précédent ou emploi similaire avec rémunération équivalente</li></ul>"},
  {num:15,title:"Le licenciement",partie:"5 — Rupture du contrat",content:"<h2>Fiche 15 — Le licenciement</h2><h3>1. Cause réelle et sérieuse</h3><p>Le motif doit être : existant, exact et objectif (faits précis et vérifiables).</p><h3>2. Types de fautes</h3><h3>3. Procédure licenciement personnel</h3><ul><li>Convocation par LRAR ou remise en main propre</li><li>Délai minimum convocation → entretien : 5 jours ouvrables</li><li>Entretien préalable : employeur expose les motifs, salarié peut être assisté</li><li>Notification par LRAR, motif précis obligatoire</li><li>Délai notification : pas moins d'1 jour franc ni plus d'1 mois après entretien</li></ul><h3>4. Licenciement économique</h3><p>Pour motifs non inhérents à la personne : difficultés économiques, mutations technologiques, réorganisation pour sauvegarder la compétitivité, cessation d'activité.</p><div class=\"key-point\">Obligation préalable de reclassement : Chercher un emploi équivalent dans l'entreprise ou le groupe avant tout licenciement économique.</div>"},
  {num:16,title:"Les autres modes de rupture",partie:"5 — Rupture du contrat",content:"<h2>Fiche 16 — Les autres modes de rupture</h2><h3>1. Démission</h3><ul><li>Volonté claire et non équivoque du salarié</li><li>Préavis obligatoire (sauf faute grave employeur)</li><li>Pas d'indemnités de licenciement</li><li>Pas de droit au chômage (sauf cas légitimes reconnus)</li></ul><h3>2. Rupture conventionnelle individuelle</h3><ul><li>Accord entre employeur et salarié</li><li>Entretien(s) préalable(s) obligatoire(s)</li><li>Délai de rétractation : 15 jours calendaires pour chaque partie</li><li>Homologation DREETS : 15 jours ouvrables</li><li>Indemnité ≥ indemnité légale de licenciement</li><li>Droit aux allocations chômage (ARE)</li></ul><h3>3. Prise d'acte de la rupture</h3><p>Salarié prend acte en raison de manquements graves de l'employeur. Le juge qualifie ensuite : licenciement sans CRS (si manquements établis) ou démission (si non établis).</p><h3>4. Mise à la retraite</h3><ul><li>Employeur peut mettre à la retraite à 70 ans sans accord</li><li>Entre 67 et 70 ans : accord du salarié requis</li></ul>"},
  {num:17,title:"Les conséquences de la rupture",partie:"5 — Rupture du contrat",content:"<h2>Fiche 17 — Les conséquences de la rupture</h2><h3>1. Préavis</h3><ul><li>Commence à la notification de la rupture</li><li>Dispense possible avec indemnité compensatrice de préavis</li><li>Durée fixée par convention collective, usage ou loi</li></ul><h3>2. Indemnité légale de licenciement</h3><p>Ancienneté minimale : 8 mois</p><h3>3. Documents de fin de contrat obligatoires</h3><ul><li>Certificat de travail : dates, emploi occupé</li><li>Attestation France Travail</li><li>Solde de tout compte : contestable dans les 6 mois</li></ul><h3>4. Clause de non-concurrence</h3><p>S'applique dès la rupture. L'employeur peut y renoncer dans le délai prévu. L'indemnité est due même en cas de démission.</p>"},
  {num:18,title:"La négociation collective",partie:"6 — Aspects collectifs",content:"<h2>Fiche 18 — La négociation collective</h2><h3>1. Hiérarchie des normes (post-ordonnances Macron)</h3><p>L'accord d'entreprise prime sur l'accord de branche, sauf dans les domaines verrouillés.</p><h3>2. Domaines verrouillés (la branche prime toujours)</h3><ul><li>Salaires minima</li><li>Classifications</li><li>Garanties collectives complémentaires</li><li>Mutualisation de la formation</li></ul><h3>3. Validité d'un accord d'entreprise</h3><p>Signé par syndicats représentant ≥ 50 % des suffrages exprimés au 1er tour des élections (ou 30 % + absence d'opposition de syndicats à 50 %).</p><h3>4. NAO — Négociations Annuelles Obligatoires</h3><ul><li>Entreprises ≥ 50 salariés avec délégué syndical</li><li>Rémunérations, temps de travail, partage de la valeur</li><li>Égalité professionnelle H/F</li></ul>"},
  {num:19,title:"Les syndicats dans l'entreprise",partie:"6 — Aspects collectifs",content:"<h2>Fiche 19 — Les syndicats dans l'entreprise</h2><h3>1. Représentativité syndicale</h3><p>Critères cumulatifs : valeurs républicaines, indépendance, transparence financière, ancienneté ≥ 2 ans, audience ≥ 10 % en entreprise (8 % au niveau national).</p><h3>2. Délégué syndical (DS)</h3><ul><li>Désigné dans entreprises ≥ 50 salariés</li><li>Représente le syndicat + négocie les accords</li><li>Heures de délégation : 12 h/mois (18 h pour 150-499 sal., 24 h pour ≥ 500)</li></ul><div class=\"key-point\">Salarié protégé : Autorisation inspecteur du travail nécessaire pendant le mandat et 12 mois après.</div>"},
  {num:20,title:"La représentation des salariés",partie:"6 — Aspects collectifs",content:"<h2>Fiche 20 — La représentation des salariés (CSE)</h2><h3>1. CSE — Seuils</h3><h3>2. Élections</h3><ul><li>Tous les 4 ans</li><li>1er tour : syndicats représentatifs uniquement</li><li>2e tour si quorum non atteint (50 %) : liste libre possible</li></ul><h3>3. Attributions (≥ 50 salariés)</h3><ul><li>Consultations obligatoires : orientations stratégiques, situation économique, politique sociale</li><li>Droits d'alerte (économique, harcèlement…)</li><li>Gestion des activités sociales et culturelles</li><li>Santé, sécurité et conditions de travail</li></ul>"},
  {num:21,title:"Le statut des représentants des salariés",partie:"6 — Aspects collectifs",content:"<h2>Fiche 21 — Le statut des représentants des salariés</h2><h3>1. Protection contre le licenciement</h3><ul><li>Autorisation préalable de l'inspecteur du travail obligatoire</li><li>Protection pendant le mandat + 6 mois après son expiration</li><li>Candidats protégés pendant 3 mois</li></ul><h3>2. Heures de délégation</h3><h3>3. Exercice du mandat</h3><ul><li>Heures de délégation = temps de travail effectif pour la rémunération</li><li>Liberté de déplacement dans et hors de l'entreprise</li><li>Non-discrimination dans la carrière</li></ul>"},
  {num:22,title:"Les conflits collectifs",partie:"6 — Aspects collectifs",content:"<h2>Fiche 22 — Les conflits collectifs</h2><h3>1. Droit de grève</h3><p>Droit constitutionnel. Cessation collective, concertée et totale du travail pour revendications professionnelles.</p><ul><li>Pas de préavis obligatoire dans le secteur privé</li><li>Suspend le contrat (ne le rompt pas)</li><li>Salaire non versé pendant la grève</li><li>Seule la faute lourde du gréviste justifie le licenciement</li></ul><div class=\"key-point\">Grèves illicites : grève politique pure, grève perlée, lock-out (en principe illicite sauf si impossible de poursuivre l'activité).</div><h3>2. Modes de résolution</h3><ul><li>Conciliation : commission paritaire</li><li>Médiation : recommandation du médiateur</li><li>Arbitrage : sentence exécutoire</li></ul>"},
  {num:23,title:"L'organisation de la Sécurité sociale",partie:"7 — Sécurité sociale",content:"<h2>Fiche 23 — Organisation du régime général</h2><h3>1. Branches du régime général</h3><h3>2. Financement</h3><ul><li>Cotisations sociales (employeur + salarié) : source principale</li><li>CSG (sur tous les revenus)</li><li>CRDS (remboursement de la dette sociale)</li></ul><h3>3. PUMA</h3><p>Protection Universelle Maladie : toute personne résidant en France a accès aux soins, quelle que soit sa situation professionnelle.</p>"},
  {num:24,title:"Les prestations sociales",partie:"7 — Sécurité sociale",content:"<h2>Fiche 24 — Les prestations sociales</h2><h3>1. Maladie</h3><ul><li>Remboursement des soins (médecin, pharmacie, hôpital)</li><li>IJ : après 3 jours de carence ; 50 % du SJR plafonné</li><li>Durée max : 3 ans selon affection (ALD : prise en charge 100 %)</li></ul><h3>2. Maternité</h3><ul><li>Soins liés à la grossesse pris en charge à 100 %</li><li>IJ maternité = 100 % du SJR plafonné</li></ul><h3>3. Invalidité</h3><h3>4. Famille</h3><ul><li>Allocations familiales : à partir de 2 enfants à charge</li><li>PAJE pour enfant &lt; 3 ans</li></ul>"},
  {num:25,title:"L'activité partielle et le chômage",partie:"8 — Assurance chômage",content:"<h2>Fiche 25 — L'activité partielle et le chômage</h2><h3>1. Activité partielle</h3><ul><li>Autorisée par la DREETS</li><li>Indemnisation salarié : 60 % de la rémunération brute</li><li>APLD : accord collectif, jusqu'à 24 mois sur 36</li></ul><h3>2. Conditions ARE (assurance chômage)</h3><ul><li>Avoir travaillé ≥ 6 mois dans les 24 derniers mois (36 pour les &gt; 53 ans)</li><li>Rupture involontaire (licenciement, fin CDD, rupture conventionnelle…)</li><li>Inscrit à France Travail, apte et en recherche active</li></ul><h3>3. Calcul de l'ARE</h3><ul><li>Basée sur le Salaire Journalier de Référence (SJR)</li><li>Entre 57 % et 75 % du SJR</li><li>Durée max : 24 mois (36 mois pour &gt; 53 ans)</li></ul><div class=\"key-point\">Délai de carence : 7 jours (+ différé d'indemnisation selon indemnités de rupture perçues).</div>"},
  {num:26,title:"L'aide sociale",partie:"9 — Aide sociale et complémentaires",content:"<h2>Fiche 26 — L'aide sociale</h2><h3>1. RSA (Revenu de Solidarité Active)</h3><ul><li>Versé par la CAF</li><li>≥ 25 ans (ou parent isolé dès 18 ans)</li><li>Obligation d'engagement dans une démarche de retour à l'emploi</li></ul><h3>2. AAH (Allocation Adulte Handicapé)</h3><ul><li>Taux d'incapacité ≥ 80 % (ou 50-80 % avec restriction d'accès à l'emploi)</li><li>Versée par la CAF sur décision de la MDPH</li></ul><h3>3. C2S (Complémentaire Santé Solidaire)</h3><p>Protection complémentaire gratuite pour personnes à faibles ressources. Prise en charge du ticket modérateur et du forfait journalier.</p><h3>4. Prime d'activité</h3><p>Complément de revenus pour les travailleurs à faibles revenus. Versée par la CAF, sans condition d'âge depuis 2019.</p>"},
  {num:27,title:"Les régimes complémentaires",partie:"9 — Aide sociale et complémentaires",content:"<h2>Fiche 27 — Les régimes complémentaires</h2><h3>1. Retraite complémentaire (AGIRC-ARRCO)</h3><ul><li>Obligatoire pour tous les salariés du secteur privé</li><li>Fonctionnement en points : cotisations → points → retraite</li><li>Gestion paritaire</li></ul><h3>2. Prévoyance complémentaire</h3><ul><li>Couvre décès, invalidité, incapacité</li><li>Obligatoire dans certaines branches</li></ul><h3>3. Complémentaire santé</h3><ul><li>Obligatoire dans toutes les entreprises privées depuis 2016</li><li>Part patronale ≥ 50 % de la cotisation</li><li>Panier de soins ANI (niveau minimal de garanties)</li></ul><div class=\"key-point\">Portabilité : En cas de rupture, le salarié conserve ses droits complémentaires pendant une durée = durée du dernier contrat (maximum 12 mois).</div>"},
  {num:28,title:"Le contentieux social",partie:"10 — Contentieux",content:"<h2>Fiche 28 — Le contentieux social</h2><h3>1. Juridictions compétentes</h3><h3>2. Procédure SS</h3><ul><li>Recours préalable obligatoire devant la CRA (Commission de recours amiable) de la CPAM</li><li>Délai de saisine : 2 mois à compter de la notification</li><li>Appel devant la Cour d'appel (chambre sociale)</li></ul><div class=\"key-point\">Aide juridictionnelle disponible selon ressources. Vérifier aussi l'assurance protection juridique de votre mutuelle.</div>"}
];

